      secenekler:[{harf:"A",metin:"Teşkilat-ı Esasiye"},{harf:"B",metin:"Hıyanet-i Vataniye Kanunu"},{harf:"C",metin:"Takrir-i Sükun"},{harf:"D",metin:"Men-i Müskirat"},{harf:"E",metin:"Ağnam Vergisi Kanunu"}],
