      secenekler:[{harf:"A",metin:"Divan-ı Harp"},{harf:"B",metin:"İstiklal Mahkemeleri"},{harf:"C",metin:"Nizamiye Mahkemeleri"},{harf:"D",metin:"Anayasa Mahkemesi"},{harf:"E",metin:"Yüce Divan"}],
