      secenekler:[{harf:"A",metin:"Musul Sorunu"},{harf:"B",metin:"Boğazlar"},{harf:"C",metin:"Hatay (Sancak) Meselesi"},{harf:"D",metin:"Nüfus Mübadelesi"},{harf:"E",metin:"Dış Borçlar"}],
